INSERT INTO public.subcontractor_applications (id, full_name, email, phone, status, why_join_us, previous_cleaning_experience, availability, emergency_contact_name, emergency_contact_phone, has_drivers_license, has_own_vehicle, can_lift_heavy_items, comfortable_with_chemicals, reliable_transportation, background_check_consent, brand_shirt_consent, subcontractor_agreement_consent, created_at, updated_at) VALUES
('660e8400-e29b-41d4-a716-446655440001', 'Maria Rodriguez', 'maria.rodriguez@email.com', '(555) 111-2222', 'pending', 'I have 5 years of residential cleaning experience and love making homes sparkle clean. I take pride in my attention to detail.', 'Yes, I worked for CleanPro Services for 3 years and have been doing private residential cleaning for 2 years.', 'Monday-Friday, 8AM-5PM', 'Carlos Rodriguez', '(555) 111-3333', true, true, true, true, true, true, true, true, '2025-01-25 09:00:00+00', '2025-01-25 09:00:00+00'),
('660e8400-e29b-41d4-a716-446655440002', 'James Thompson', 'james.thompson@email.com', '(555) 222-3333', 'approved', 'Looking for flexible work that allows me to help people. I am very reliable and thorough in my work.', 'New to professional cleaning but very detail-oriented and eager to learn.', 'Weekdays and weekends, flexible hours', 'Susan Thompson', '(555) 222-4444', true, true, true, true, true, true, true, true, '2025-01-20 14:30:00+00', '2025-01-22 10:15:00+00'),
('660e8400-e29b-41d4-a716-446655440003', 'Angela Chen', 'angela.chen@email.com', '(555) 333-4444', 'rejected', 'I need part-time work and cleaning seems easy enough.', 'No professional experience.', 'Only weekends', 'Kevin Chen', '(555) 333-5555', false, false, false, false, false, false, false, false, '2025-01-18 16:20:00+00', '2025-01-19 11:30:00+00'),
('660e8400-e29b-41d4-a716-446655440004', 'Marcus Johnson', 'marcus.johnson@email.com', '(555) 444-5555', 'pending', 'I have experience in commercial cleaning and want to transition to residential. I am very professional and reliable.', 'Yes, 4 years commercial cleaning experience with BuildingCare Inc.', 'Monday-Saturday, 7AM-6PM', 'Patricia Johnson', '(555) 444-6666', true, true, true, true, true, true, true, true, '2025-01-28 12:45:00+00', '2025-01-28 12:45:00+00'),
('660e8400-e29b-41d4-a716-446655440005', 'Rebecca White', 'rebecca.white@email.com', '(555) 555-6666', 'approved', 'I love organizing and cleaning. It brings me joy to help families have clean, comfortable homes.', 'Yes, I ran my own small cleaning business for 2 years before moving here.', 'Flexible, prefer mornings', 'David White', '(555) 555-7777', true, true, true, true, true, true, true, true, '2025-01-15 08:15:00+00', '2025-01-17 09:20:00+00');
